import{c as r,Z as o,Q as l,j as i,g as t,n,o as s,m as d}from"./chunks/framework.qjzPVSkb.js";const _=JSON.parse('{"title":"自注意力机制","description":"Transformer 的核心创新——让每个词能直接关注序列中所有其他词，通过 Query/Key/Value 计算动态权重","frontmatter":{"title":"自注意力机制","description":"Transformer 的核心创新——让每个词能直接关注序列中所有其他词，通过 Query/Key/Value 计算动态权重","difficulty":"intermediate"},"headers":[],"relativePath":"terms/self-attention.md","filePath":"terms/self-attention.md"}'),u={name:"terms/self-attention.md"};function m(f,e,h,c,q,g){const a=o("DifficultyBadge");return l(),i("div",null,[e[0]||(e[0]=t("h1",{id:"自注意力机制",tabindex:"-1"},[n("自注意力机制 "),t("a",{class:"header-anchor",href:"#自注意力机制","aria-label":'Permalink to "自注意力机制"'},"​")],-1)),s(a,{level:"intermediate"}),e[1]||(e[1]=d('<h2 id="一句话解释" tabindex="-1">一句话解释 <a class="header-anchor" href="#一句话解释" aria-label="Permalink to &quot;一句话解释&quot;">​</a></h2><p>自注意力机制（Self-Attention）是 Transformer 架构的核心，它让输入序列中的<strong>每个词都能直接关注到所有其他词</strong>，并通过 Query/Key/Value 三个矩阵动态计算每个词对其他词的重要性权重。</p><h2 id="通俗类比" tabindex="-1">通俗类比 <a class="header-anchor" href="#通俗类比" aria-label="Permalink to &quot;通俗类比&quot;">​</a></h2><p>阅读一段长文章时，你会自然地对关键词划线、标记重点——看到&quot;因此&quot;就知道前面有原因，看到&quot;但是&quot;就知道后面有转折。自注意力机制做的就是类似的事：对于句子中的每个词，模型自动计算它和其他所有词之间的&quot;关联度&quot;，然后把注意力集中在最相关的词上。如果句子是&quot;猫坐在垫子上因为它很舒服&quot;，自注意力会让&quot;它&quot;和&quot;垫子&quot;之间的关联权重很高，从而正确理解&quot;它&quot;指的是垫子而不是猫。</p><h2 id="技术定义" tabindex="-1">技术定义 <a class="header-anchor" href="#技术定义" aria-label="Permalink to &quot;技术定义&quot;">​</a></h2><p>自注意力的计算过程分为三步：</p><ol><li><strong>构造 Q、K、V 矩阵</strong>：每个词的词向量分别乘以三个可训练的权重矩阵，得到 Query（查询）、Key（键）、Value（值）向量</li><li><strong>计算注意力分数</strong>：用当前词的 Q 向量去和所有词的 K 向量做点积，得到一个分数，表示当前词与每个其他词的相关程度。分数经过缩放（除以 √dₖ）和 Softmax 归一化，得到注意力权重</li><li><strong>加权求和</strong>：用注意力权重对所有词的 V 向量做加权求和，得到当前词的最终输出表示</li></ol><p><strong>多头自注意力（Multi-Head Self-Attention）</strong> 是这一机制的扩展——同时运行多组独立的 Q/K/V 计算（每个称为一个&quot;头&quot;），每个头可以关注不同的语义关系（如语法结构、指代关系、语义相似性等），最后拼接所有头的输出。</p><h2 id="关联术语" tabindex="-1">关联术语 <a class="header-anchor" href="#关联术语" aria-label="Permalink to &quot;关联术语&quot;">​</a></h2><ul><li><a href="/ai-knowledge/terms/transformer.html">Transformer</a> —— 自注意力是 Transformer 的核心组件</li><li><a href="/ai-knowledge/terms/kv-cache.html">KV Cache</a> —— 自注意力中 K、V 矩阵的缓存优化</li><li><a href="/ai-knowledge/terms/llm.html">大语言模型 (LLM)</a> —— 所有 LLM 都依赖自注意力理解上下文</li><li><a href="/ai-knowledge/terms/embedding.html">Embedding</a> —— 自注意力的输入是从词嵌入开始计算的</li></ul><h2 id="延伸阅读" tabindex="-1">延伸阅读 <a class="header-anchor" href="#延伸阅读" aria-label="Permalink to &quot;延伸阅读&quot;">​</a></h2><ul><li>原论文中的 Self-Attention 章节：<a href="https://arxiv.org/abs/1706.03762" target="_blank" rel="noreferrer">Attention Is All You Need</a> §3.2</li><li>Jay Alammar 图解：<a href="https://jalammar.github.io/illustrated-transformer/" target="_blank" rel="noreferrer">The Illustrated Transformer</a> —— 非常直观的注意力可视化</li><li>动手理解：用 🤗 Transformers 库的 <code>bertviz</code> 工具可视化 BERT 的注意力权重</li></ul>',12))])}const b=r(u,[["render",m]]);export{_ as __pageData,b as default};
